var playwrightMod3 = await import('playwright');
var chromeBrowser2 = await playwrightMod3.chromium.launch({ headless: true, executablePath: '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome' });
var chromePage2 = await chromeBrowser2.newPage({ viewport: { width: 1280, height: 720 }, deviceScaleFactor: 1 });
var failedResponses = [];
var pageErrors3 = [];
chromePage2.on('response', (response) => {
  if (response.status() >= 400) failedResponses.push({ url: response.url(), status: response.status() });
});
chromePage2.on('pageerror', (error) => pageErrors3.push(error.message));
await chromePage2.goto('http://127.0.0.1:5173/leaderboard', { waitUntil: 'domcontentloaded' });
await chromePage2.waitForSelector('.leaderboard.is-board:not(.hidden)', { timeout: 10000 });
await chromePage2.locator('[data-lb-back]').click();
await chromePage2.waitForURL('http://127.0.0.1:5173/', { timeout: 10000 });
await chromePage2.waitForSelector('#title-screen:not(.hidden)', { timeout: 10000 });
var backState = await chromePage2.evaluate(() => ({
  pathname: window.location.pathname,
  titleVisible: !document.getElementById('title-screen')?.classList.contains('hidden'),
  leaderboardVisible: !!document.querySelector('.leaderboard:not(.hidden)'),
  bodyClass: document.body.className,
}));
await chromeBrowser2.close();
nodeRepl.write(JSON.stringify({ failedResponses, pageErrors: pageErrors3, backState }, null, 2));

