var overlapBrowser = await pwOverlap.chromium.launch({ headless: true, executablePath: '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome' });
var overlapPage = await overlapBrowser.newPage({ viewport: { width: 2048, height: 800 }, deviceScaleFactor: 1 });
var overlapErrors = [];
overlapPage.on('pageerror', (error) => overlapErrors.push(error.message));
await overlapPage.goto('http://127.0.0.1:5173/leaderboard', { waitUntil: 'domcontentloaded' });
await overlapPage.waitForSelector('.leaderboard.is-board:not(.hidden) .lb-row:nth-child(10)', { timeout: 10000 });
await overlapPage.waitForTimeout(1000);
var overlapState = await overlapPage.evaluate(() => {
  const row1Score = document.querySelector('.lb-row:nth-child(1) .lb-points');
  const row6Rank = document.querySelector('.lb-row:nth-child(6) .lb-rank');
  const row1ScoreRect = row1Score.getBoundingClientRect();
  const row6RankRect = row6Rank.getBoundingClientRect();
  return {
    firstScore: row1Score.textContent,
    firstScoreClass: row1Score.className,
    scoreRight: Math.round(row1ScoreRect.right),
